import{_ as i,o as t,c as o,aA as a}from"./chunks/framework.CPxl66na.js";const u=JSON.parse('{"title":"Options limitations / IBKR mapping","description":"","frontmatter":{},"headers":[],"relativePath":"options_limitations.md","filePath":"options_limitations.md","lastUpdated":null}'),n={name:"options_limitations.md"};function r(s,e,l,p,c,d){return t(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="Options-limitations-/-IBKR-mapping" tabindex="-1">Options limitations / IBKR mapping <a class="header-anchor" href="#Options-limitations-/-IBKR-mapping" aria-label="Permalink to &quot;Options limitations / IBKR mapping {#Options-limitations-/-IBKR-mapping}&quot;">​</a></h1><p>Fastback&#39;s listed option support is deterministic and accounting-focused. It is useful for researching premium flows, mark-to-market P&amp;L, spread margin behavior, expiry cashflows, and liquidation mechanics. It is not a full OCC, exchange, or broker lifecycle simulator.</p><h2 id="What-Fastback-Models" tabindex="-1">What Fastback Models <a class="header-anchor" href="#What-Fastback-Models" aria-label="Permalink to &quot;What Fastback Models {#What-Fastback-Models}&quot;">​</a></h2><ul><li><p>Quote-driven listed option positions with bid, ask, and last marks.</p></li><li><p>Premium cash accounting in the option settlement currency.</p></li><li><p>Underlying marks through <code>OptionUnderlyingUpdate</code> and <code>update_option_underlying_price!</code>.</p></li><li><p>Cash settlement at intrinsic value through <code>settle_option_expiry!</code> and <code>process_expiries!</code>.</p></li><li><p>Short-option margin plus bounded multi-leg margin relief for same-underlying option groups.</p></li><li><p>Atomic package preflight through <code>fill_option_strategy!</code>.</p></li><li><p>Broker-profile commissions and financing where configured, for example through <code>IBKRProFixedBroker</code>.</p></li></ul><h2 id="Important-Limitations" tabindex="-1">Important Limitations <a class="header-anchor" href="#Important-Limitations" aria-label="Permalink to &quot;Important Limitations {#Important-Limitations}&quot;">​</a></h2><p>All option expiries in Fastback are cash-settled by the engine. This applies even when the symbols and examples look like SPY, AAPL, or other US equity or ETF options.</p><p>Fastback does not currently model:</p><ul><li><p>Physical delivery of shares, ETF units, futures, or other underlyings.</p></li><li><p>Early exercise decisions.</p></li><li><p>Short assignment.</p></li><li><p>Pin risk or random assignment around expiry.</p></li><li><p>Exercise notices, OCC adjustments, corporate actions, or deliverable changes.</p></li><li><p>Stock borrow, hard-to-borrow state, or short-stock positions created by assignment.</p></li><li><p>Broker-specific portfolio margin, TIMS, SPAN, or real-time house margin engines.</p></li></ul><p><code>OptionExerciseStyle.American</code> and <code>OptionExerciseStyle.European</code> are instrument metadata today. They validate option instruments, but they do not change expiry processing or create exercise and assignment events.</p><h2 id="IBKR-Mapping" tabindex="-1">IBKR Mapping <a class="header-anchor" href="#IBKR-Mapping" aria-label="Permalink to &quot;IBKR Mapping {#IBKR-Mapping}&quot;">​</a></h2><p><code>IBKRProFixedBroker</code> is an IBKR-style commission and financing profile. It should not be read as an implementation of the full IBKR account model.</p><p>For an IBKR-sourced US equity-option backtest, the usual mapping is:</p><ul><li><p>Contract metadata maps to <code>option_instrument</code>: underlying, expiry, right, strike, multiplier, quote currency, and settlement currency.</p></li><li><p>Quote rows map to <code>MarkUpdate</code> values for bid, ask, and last.</p></li><li><p>Underlying reference prices map to <code>OptionUnderlyingUpdate</code>.</p></li><li><p>Single-leg fills map to <code>fill_order!</code>; package fills map to <code>fill_option_strategy!</code>.</p></li><li><p><code>IBKRProFixedBroker</code> applies the option order minimum once across <code>fill_option_strategy!</code> packages by default, while regulatory/pass-through fees remain per leg. Set <code>option_strategy_commission=OptionStrategyCommissionMode.PerLegOrders</code> on the broker to model legged execution costs.</p></li><li><p>Expiry and assignment do not map one-to-one. Fastback uses model-side cash intrinsic settlement, while many US equity and ETF options are American-style and physically settled.</p></li><li><p>Margin should be treated as an internal model result. Reconcile it against broker statements before using it for broker-report matching or production risk limits.</p></li></ul><h2 id="Practical-Guidance" tabindex="-1">Practical Guidance <a class="header-anchor" href="#Practical-Guidance" aria-label="Permalink to &quot;Practical Guidance {#Practical-Guidance}&quot;">​</a></h2><ul><li><p>Label SPY-like or AAPL-like option examples as cash-settled proxies.</p></li><li><p>Close or roll positions before expiry when assignment, delivery, or dividend-sensitive exercise behavior matters to the research question.</p></li><li><p>Do not interpret Fastback expiry trades as assigned stock trades.</p></li><li><p>Treat expiry cashflows as model cashflows, not broker statement events.</p></li><li><p>Use <code>check_invariants(acc)</code> in tests when adding option accounting, margin, expiry, or liquidation behavior.</p></li></ul>',15)])])}const h=i(n,[["render",r]]);export{u as __pageData,h as default};
